    function _tryParseChr(bytes1 chr) private pure returns (uint8) {
        uint8 value = uint8(chr);

        // Try to parse `chr`:
        // - Case 1: [0-9]
        // - Case 2: [a-f]
        // - Case 3: [A-F]
        // - otherwise not supported
        unchecked {
            if (value > 47 && value < 58) value -= 48;
            else if (value > 96 && value < 103) value -= 87;
            else if (value > 64 && value < 71) value -= 55;
            else return type(uint8).max;
        }

        return value;
    }

    /**
     * @dev Escape special characters in JSON strings. This can be useful to prevent JSON injection in NFT metadata.
     *
     * WARNING: This function should only be used in double quoted JSON strings. Single quotes are not escaped.
     *
     * NOTE: This function escapes backslashes (including those in \uXXXX sequences) and the characters in ranges
     * defined in section 2.5 of RFC-4627 (U+0000 to U+001F, U+0022 and U+005C). All control characters in U+0000
     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/AccessPassNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import {ERC721} from "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/// @title AccessPassNFT
/// @notice ネットカフェ利用権を表すNFTコントラクト
/// @dev ERC721を継承し、利用権の発行・消費・譲渡クールダウンを管理する
contract AccessPassNFT is ERC721, Ownable {
    // -----------------------------------------------------------------------
    // 定数
    // -----------------------------------------------------------------------

    /// @notice 譲渡クールダウン期間（マネロン防止）
    uint256 public constant TRANSFER_COOLDOWN = 24 hours;

    // -----------------------------------------------------------------------
    // 状態変数
    // -----------------------------------------------------------------------

    /// @notice オペレータアドレス（通常はバックエンドサービス）
    address public operator;

    /// @notice 次のトークンID（1始まり）
    uint256 public nextTokenId = 1;

    /// @notice パスの詳細データ構造体
    struct PassData {
        uint256 planId;           // 料金プランID
        uint256 venueId;          // 対象店舗ID（0なら複数店舗共通）
        uint256 remainingMinutes; // 残り利用時間（分）
        uint256 expiresAt;        // 有効期限（UNIXタイムスタンプ）
        bool    isActive;         // 有効フラグ
        bool    transferable;     // 譲渡可能フラグ（月額プランは false）
    }

    /// @notice tokenId → PassData のマッピング
    mapping(uint256 => PassData) public passes;

    /// @notice tokenId → 最終譲渡タイムスタンプ（クールダウン計算用）
    mapping(uint256 => uint256) public lastTransferTime;

    // -----------------------------------------------------------------------
    // カスタムエラー
    // -----------------------------------------------------------------------

    error NotOperator();
    error ZeroAddress();
    error PassExpired();
    error PassInactive();
    error NotTransferable();
    error CooldownActive(uint256 availableAt);
    error InsufficientRemainingMinutes();
    error InvalidDuration();

    // -----------------------------------------------------------------------
    // イベント
    // -----------------------------------------------------------------------

    event OperatorUpdated(address indexed operator);

    /// @notice パスがミントされた時に発行
    event PassMinted(
        uint256 indexed tokenId,
        address indexed to,
        uint256 planId,
        uint256 venueId,
        uint256 durationMinutes,
        uint256 expiresAt,
        bool    transferable
    );

    /// @notice パスが消費（使用）された時に発行
    event PassConsumed(
        uint256 indexed tokenId,
        uint256 usedMinutes,
        uint256 remainingMinutes
    );

    /// @notice パスが一時停止された時に発行（紛争・不正対応）
    event PassSuspended(uint256 indexed tokenId);

    /// @notice パスが再有効化された時に発行
    event PassReactivated(uint256 indexed tokenId);

    // -----------------------------------------------------------------------
    // コンストラクタ
    // -----------------------------------------------------------------------

    constructor(string memory name_, string memory symbol_)
        ERC721(name_, symbol_)
        Ownable(msg.sender)
    {}

    // -----------------------------------------------------------------------
    // 修飾子
    // -----------------------------------------------------------------------

    modifier onlyOperator() {
        if (msg.sender != operator) revert NotOperator();
        _;
    }

    // -----------------------------------------------------------------------
    // 管理関数（Owner）
    // -----------------------------------------------------------------------

    /// @notice オペレータアドレスを設定する
    /// @param operator_ 新しいオペレータアドレス
    function setOperator(address operator_) external onlyOwner {
        if (operator_ == address(0)) revert ZeroAddress();
        operator = operator_;
        emit OperatorUpdated(operator_);
    }

    // -----------------------------------------------------------------------
    // オペレータ関数
    // -----------------------------------------------------------------------

    /// @notice 利用権NFTを発行する
    /// @param to            受取アドレス
    /// @param planId        料金プランID
    /// @param venueId       対象店舗ID（0=複数店舗共通）
    /// @param durationMinutes 基本利用時間（分）
    /// @param expiresAt     有効期限（UNIXタイムスタンプ）
    /// @param transferable_ 譲渡可能フラグ
    /// @return tokenId      発行されたトークンID
    function mint(
        address to,
        uint256 planId,
        uint256 venueId,
        uint256 durationMinutes,
        uint256 expiresAt,
        bool    transferable_
    ) external onlyOperator returns (uint256 tokenId) {
        if (to == address(0)) revert ZeroAddress();
        if (durationMinutes == 0) revert InvalidDuration();
        if (expiresAt <= block.timestamp) revert PassExpired();

        tokenId = nextTokenId++;
        _safeMint(to, tokenId);

        passes[tokenId] = PassData({
            planId:           planId,
            venueId:          venueId,
            remainingMinutes: durationMinutes,
            expiresAt:        expiresAt,
            isActive:         true,
            transferable:     transferable_
        });

        emit PassMinted(tokenId, to, planId, venueId, durationMinutes, expiresAt, transferable_);
    }

    /// @notice パスを消費する（チェックアウト時にオペレータが呼び出す）
    /// @param tokenId     対象トークンID
    /// @param usedMinutes 実際に使用した時間（分）
    function consumePass(uint256 tokenId, uint256 usedMinutes) external onlyOperator {
        PassData storage pass = passes[tokenId];

        if (!pass.isActive)                    revert PassInactive();
        if (block.timestamp >= pass.expiresAt) revert PassExpired();
        if (usedMinutes > pass.remainingMinutes) revert InsufficientRemainingMinutes();

        unchecked {
            pass.remainingMinutes -= usedMinutes;
        }

        // 残り0分になったら無効化
        if (pass.remainingMinutes == 0) {
            pass.isActive = false;
        }

        emit PassConsumed(tokenId, usedMinutes, pass.remainingMinutes);
    }

    /// @notice パスを一時停止する（紛争・不正使用対応）
    /// @param tokenId 対象トークンID
    function suspendPass(uint256 tokenId) external onlyOperator {
        passes[tokenId].isActive = false;
        emit PassSuspended(tokenId);
    }

    /// @notice パスを再有効化する
    /// @param tokenId 対象トークンID
    function reactivatePass(uint256 tokenId) external onlyOperator {
        passes[tokenId].isActive = true;
        emit PassReactivated(tokenId);
    }

    // -----------------------------------------------------------------------
    // 内部関数
    // -----------------------------------------------------------------------

    /// @notice ERC721転送フック：譲渡可否・クールダウンをチェックする
    /// @dev _update はミント・転送・バーン全てで呼ばれる
    function _update(address to, uint256 tokenId, address auth)
        internal
        virtual
        override
        returns (address)
    {
        address from = _ownerOf(tokenId);

        // ミント時（from == address(0)）はスキップ
        if (from != address(0)) {
            PassData storage pass = passes[tokenId];

            // 譲渡不可チェック
            if (!pass.transferable) revert NotTransferable();

            // クールダウンチェック
            uint256 availableAt = lastTransferTime[tokenId] + TRANSFER_COOLDOWN;
            if (block.timestamp < availableAt) revert CooldownActive(availableAt);

            // 譲渡時刻を記録
            lastTransferTime[tokenId] = block.timestamp;
        }

        return super._update(to, tokenId, auth);
    }

    // -----------------------------------------------------------------------
    // ビュー関数
    // -----------------------------------------------------------------------

    /// @notice パスデータを取得する
    /// @param tokenId 対象トークンID
    function getPass(uint256 tokenId) external view returns (PassData memory) {
        return passes[tokenId];
    }

    /// @notice パスが現在有効かどうかを確認する
    /// @param tokenId 対象トークンID
    /// @return true = 有効・利用可能
    function isPassValid(uint256 tokenId) external view returns (bool) {
        PassData storage pass = passes[tokenId];
        return pass.isActive
            && block.timestamp < pass.expiresAt
            && pass.remainingMinutes > 0;
    }
}

contracts/ComputeMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title ComputeMarket
/// @notice 遊休算力マーケットプレイス
/// @dev ノードID（bytes32）をオンチェーン管理し、ジョブのライフサイクルと自動収益分配を処理する
contract ComputeMarket is Ownable, ReentrancyGuard {
    // -----------------------------------------------------------------------
    // 定数
    // -----------------------------------------------------------------------

    /// @notice プラットフォーム手数料（25%）
    uint256 public constant PLATFORM_FEE_BPS = 250;

    /// @notice 手数料計算の分母（1000 = 100%）
    uint256 public constant FEE_DENOMINATOR = 1000;

    // -----------------------------------------------------------------------
    // 状態変数
    // -----------------------------------------------------------------------

    /// @notice 決済トークン（JPYC）
    IERC20 public immutable token;

    /// @notice オペレータアドレス（バックエンドサービス）
    address public operator;

    /// @notice プラットフォーム手数料の受取アドレス
    address public platformFeeRecipient;

    /// @notice 次のジョブID（1始まり）
    uint256 public nextJobId = 1;

    /// @notice ジョブステータスの列挙型
    enum JobStatus {
        PENDING,    // 依頼済み・マッチング待ち
        ASSIGNED,   // ノードにアサイン済み
        RUNNING,    // 実行中
        COMPLETED,  // 完了（収益分配済み）
        FAILED,     // 失敗（全額返金済み）
        CANCELLED   // キャンセル（全額返金済み）
    }

    /// @notice ノードの詳細データ構造体
    struct NodeData {
        address venueOwner;         // ノード所有店舗のアドレス
        uint256 pricePerHourMinor;  // 1時間あたりの料金（JPYCマイナー単位）
        uint256 minBookingHours;    // 最小予約時間
        uint256 maxBookingHours;    // 最大予約時間
        bool    active;             // 受付中フラグ
    }

    /// @notice ジョブの詳細データ構造体
    struct JobData {
        bytes32 nodeId;         // 対象ノードID
        address requester;      // 依頼者アドレス
        uint256 depositMinor;   // エスクロー金額（JPYCマイナー単位）
        uint256 estimatedHours; // 予約時間数
        uint256 startedAt;      // 実行開始タイムスタンプ（0=未開始）
        uint256 endedAt;        // 終了タイムスタンプ（0=未終了）
        JobStatus status;       // 現在のステータス
        bytes32 resultHash;     // 成果物ハッシュ（完了時のみ）
    }

    /// @notice nodeId → NodeData のマッピング
    mapping(bytes32 => NodeData) public nodes;

    /// @notice jobId → JobData のマッピング
    mapping(uint256 => JobData) public jobs;

    /// @notice 登録済みノードIDの一覧（列挙用）
    bytes32[] public nodeIds;

    // -----------------------------------------------------------------------
    // カスタムエラー
    // -----------------------------------------------------------------------

    error NotOperator();
    error ZeroAddress();
    error NodeNotFound();
    error NodeAlreadyExists();
    error NodeNotActive();
    error InvalidBookingHours();
    error InvalidPrice();
    error JobNotFound();
    error InvalidJobTransition();
    error NotRequesterOrOperator();

    // -----------------------------------------------------------------------
    // イベント
    // -----------------------------------------------------------------------

    event OperatorUpdated(address indexed operator);
    event PlatformFeeRecipientUpdated(address indexed recipient);

    /// @notice ノードが登録された時に発行
    event NodeRegistered(
        bytes32 indexed nodeId,
        address indexed venueOwner,
        uint256 pricePerHourMinor
    );

    /// @notice ノード情報が更新された時に発行
    event NodeUpdated(bytes32 indexed nodeId);

    /// @notice ノードが無効化された時に発行
    event NodeDeactivated(bytes32 indexed nodeId);

    /// @notice ノードが有効化された時に発行
    event NodeActivated(bytes32 indexed nodeId);

    /// @notice ジョブが依頼された時に発行
    event JobSubmitted(
        uint256 indexed jobId,
        bytes32 indexed nodeId,
        address indexed requester,
        uint256 depositMinor
    );

    /// @notice ジョブがアサインされた時に発行
    event JobAssigned(uint256 indexed jobId);

    /// @notice ジョブが開始された時に発行
    event JobStarted(uint256 indexed jobId, uint256 startedAt);

    /// @notice ジョブが完了し収益が分配された時に発行
    event JobCompleted(
        uint256 indexed jobId,
        bytes32 resultHash,
        uint256 venueAmount,
        uint256 platformAmount
    );

    /// @notice ジョブが失敗し返金された時に発行
    event JobFailed(uint256 indexed jobId, uint256 refundAmount);

    /// @notice ジョブがキャンセルされ返金された時に発行
    event JobCancelled(uint256 indexed jobId, uint256 refundAmount);

    // -----------------------------------------------------------------------
    // 修飾子
    // -----------------------------------------------------------------------

    modifier onlyOperator() {
        if (msg.sender != operator) revert NotOperator();
        _;
    }

    // -----------------------------------------------------------------------
    // コンストラクタ
    // -----------------------------------------------------------------------

    constructor(address token_, address platformFeeRecipient_) Ownable(msg.sender) {
        if (token_ == address(0)) revert ZeroAddress();
        if (platformFeeRecipient_ == address(0)) revert ZeroAddress();
        token = IERC20(token_);
        platformFeeRecipient = platformFeeRecipient_;
    }

    // -----------------------------------------------------------------------
    // 管理関数（Owner）
    // -----------------------------------------------------------------------

    /// @notice オペレータアドレスを設定する
    function setOperator(address operator_) external onlyOwner {
        if (operator_ == address(0)) revert ZeroAddress();
        operator = operator_;
        emit OperatorUpdated(operator_);
    }

    /// @notice プラットフォーム手数料受取アドレスを設定する
    function setPlatformFeeRecipient(address recipient_) external onlyOwner {
        if (recipient_ == address(0)) revert ZeroAddress();
        platformFeeRecipient = recipient_;
        emit PlatformFeeRecipientUpdated(recipient_);
    }

    // -----------------------------------------------------------------------
    // ノード管理関数（Operator）
    // -----------------------------------------------------------------------

    /// @notice ノードを新規登録する
    /// @param nodeId       keccak256ハッシュ（オフチェーンIDのオンチェーン表現）
    /// @param venueOwner   ノード所有店舗のアドレス
    /// @param pricePerHourMinor 1時間あたりの料金（JPYCマイナー単位）
    /// @param minBookingHours  最小予約時間数
    /// @param maxBookingHours  最大予約時間数
    function registerNode(
        bytes32 nodeId,
        address venueOwner,
        uint256 pricePerHourMinor,
        uint256 minBookingHours,
        uint256 maxBookingHours
    ) external onlyOperator {
        if (nodes[nodeId].venueOwner != address(0)) revert NodeAlreadyExists();
        if (venueOwner == address(0)) revert ZeroAddress();
        if (pricePerHourMinor == 0) revert InvalidPrice();
        if (minBookingHours == 0 || minBookingHours > maxBookingHours) revert InvalidBookingHours();

        nodes[nodeId] = NodeData({
            venueOwner:        venueOwner,
            pricePerHourMinor: pricePerHourMinor,
            minBookingHours:   minBookingHours,
            maxBookingHours:   maxBookingHours,
            active:            true
        });
        nodeIds.push(nodeId);

        emit NodeRegistered(nodeId, venueOwner, pricePerHourMinor);
    }

    /// @notice ノードの料金・時間設定を更新する
    function updateNode(
        bytes32 nodeId,
        uint256 pricePerHourMinor,
        uint256 minBookingHours,
        uint256 maxBookingHours
    ) external onlyOperator {
        NodeData storage node = nodes[nodeId];
        if (node.venueOwner == address(0)) revert NodeNotFound();
        if (pricePerHourMinor == 0) revert InvalidPrice();
        if (minBookingHours == 0 || minBookingHours > maxBookingHours) revert InvalidBookingHours();

        node.pricePerHourMinor = pricePerHourMinor;
        node.minBookingHours   = minBookingHours;
        node.maxBookingHours   = maxBookingHours;

        emit NodeUpdated(nodeId);
    }

    /// @notice ノードを無効化する（新規ジョブ受付停止）
    function deactivateNode(bytes32 nodeId) external onlyOperator {
        if (nodes[nodeId].venueOwner == address(0)) revert NodeNotFound();
        nodes[nodeId].active = false;
        emit NodeDeactivated(nodeId);
    }

    /// @notice ノードを有効化する（新規ジョブ受付再開）
    function activateNode(bytes32 nodeId) external onlyOperator {
        if (nodes[nodeId].venueOwner == address(0)) revert NodeNotFound();
        nodes[nodeId].active = true;
        emit NodeActivated(nodeId);
    }

    // -----------------------------------------------------------------------
    // ジョブライフサイクル関数
    // -----------------------------------------------------------------------

    /// @notice ジョブを依頼する（JPYCをエスクローに預け入れ）
    /// @param nodeId        対象ノードID
    /// @param estimatedHours 予約時間数
    /// @return jobId         発行されたジョブID
    function submitJob(
        bytes32 nodeId,
        uint256 estimatedHours
    ) external nonReentrant returns (uint256 jobId) {
        NodeData storage node = nodes[nodeId];
        if (node.venueOwner == address(0)) revert NodeNotFound();
        if (!node.active) revert NodeNotActive();
        if (
            estimatedHours < node.minBookingHours ||
            estimatedHours > node.maxBookingHours
        ) revert InvalidBookingHours();

        uint256 depositMinor = node.pricePerHourMinor * estimatedHours;
        bool ok = token.transferFrom(msg.sender, address(this), depositMinor);
        require(ok, "transferFrom failed");

        jobId = nextJobId++;
        jobs[jobId] = JobData({
            nodeId:         nodeId,
            requester:      msg.sender,
            depositMinor:   depositMinor,
            estimatedHours: estimatedHours,
            startedAt:      0,
            endedAt:        0,
            status:         JobStatus.PENDING,
            resultHash:     bytes32(0)
        });

        emit JobSubmitted(jobId, nodeId, msg.sender, depositMinor);
    }

    /// @notice ジョブをノードにアサインする（PENDING → ASSIGNED）
    function assignJob(uint256 jobId) external onlyOperator {
        JobData storage job = jobs[jobId];
        if (job.requester == address(0)) revert JobNotFound();
        if (job.status != JobStatus.PENDING) revert InvalidJobTransition();

        job.status = JobStatus.ASSIGNED;
        emit JobAssigned(jobId);
    }

    /// @notice ジョブの実行を開始する（ASSIGNED → RUNNING）
    function startJob(uint256 jobId) external onlyOperator {
        JobData storage job = jobs[jobId];
        if (job.requester == address(0)) revert JobNotFound();
        if (job.status != JobStatus.ASSIGNED) revert InvalidJobTransition();

        job.status    = JobStatus.RUNNING;
        job.startedAt = block.timestamp;
        emit JobStarted(jobId, block.timestamp);
    }

    /// @notice ジョブを完了し収益を自動分配する（RUNNING → COMPLETED）
    /// @dev 店舗75% / プラットフォーム25%
    function completeJob(uint256 jobId, bytes32 resultHash) external nonReentrant onlyOperator {
        JobData storage job = jobs[jobId];
        if (job.requester == address(0)) revert JobNotFound();
        if (job.status != JobStatus.RUNNING) revert InvalidJobTransition();

        job.status     = JobStatus.COMPLETED;
        job.endedAt    = block.timestamp;
        job.resultHash = resultHash;

        uint256 deposit      = job.depositMinor;
        uint256 platformFee  = (deposit * PLATFORM_FEE_BPS) / FEE_DENOMINATOR;
        uint256 venueAmount  = deposit - platformFee;

        address venueOwner = nodes[job.nodeId].venueOwner;

        bool ok1 = token.transfer(venueOwner, venueAmount);
        require(ok1, "venue transfer failed");

        bool ok2 = token.transfer(platformFeeRecipient, platformFee);
        require(ok2, "platform transfer failed");

        emit JobCompleted(jobId, resultHash, venueAmount, platformFee);
    }

    /// @notice ジョブ失敗を記録し全額返金する（ASSIGNED/RUNNING → FAILED）
    function failJob(uint256 jobId) external nonReentrant onlyOperator {
        JobData storage job = jobs[jobId];
        if (job.requester == address(0)) revert JobNotFound();
        if (job.status != JobStatus.RUNNING && job.status != JobStatus.ASSIGNED)
            revert InvalidJobTransition();

        uint256 refund    = job.depositMinor;
        address requester = job.requester;

        job.status  = JobStatus.FAILED;
        job.endedAt = block.timestamp;

        bool ok = token.transfer(requester, refund);
        require(ok, "refund failed");

        emit JobFailed(jobId, refund);
    }

    /// @notice ジョブをキャンセルし全額返金する（PENDING/ASSIGNED → CANCELLED）
    /// @dev 依頼者本人またはオペレータのみキャンセル可
    function cancelJob(uint256 jobId) external nonReentrant {
        JobData storage job = jobs[jobId];
        if (job.requester == address(0)) revert JobNotFound();
        if (msg.sender != job.requester && msg.sender != operator)
            revert NotRequesterOrOperator();
        if (job.status != JobStatus.PENDING && job.status != JobStatus.ASSIGNED)
            revert InvalidJobTransition();

        uint256 refund    = job.depositMinor;
        address requester = job.requester;

        job.status = JobStatus.CANCELLED;

        bool ok = token.transfer(requester, refund);
        require(ok, "refund failed");

        emit JobCancelled(jobId, refund);
    }

    // -----------------------------------------------------------------------
    // ビュー関数
    // -----------------------------------------------------------------------

    /// @notice ノードデータを取得する
    function getNode(bytes32 nodeId) external view returns (NodeData memory) {
        return nodes[nodeId];
    }

    /// @notice ジョブデータを取得する
    function getJob(uint256 jobId) external view returns (JobData memory) {
        return jobs[jobId];
    }

    /// @notice 登録済みノード数を返す
    function getNodeCount() external view returns (uint256) {
        return nodeIds.length;
    }
}

